class BitVectorFreeSpace:
    def __init__(self, num_blocks):
        self.num_blocks = num_blocks
        self.bitmap = [0] * num_blocks  # 0 = free, 1 = allocated

    def allocate_block(self):
        """Find first free block and allocate it"""
        for i in range(self.num_blocks):
            if self.bitmap[i] == 0:
                self.bitmap[i] = 1
                return i
        return -1  # No free block

    def free_block(self, block_num):
        """Mark a block as free"""
        if 0 <= block_num < self.num_blocks:
            self.bitmap[block_num] = 0
            return True
        return False

    def get_free_blocks_count(self):
        """Count total free blocks"""
        return self.bitmap.count(0)

    def print_bitmap(self):
        """Display bitmap status"""
        print("Block:", end=" ")
        for i in range(self.num_blocks):
            print(i, end=" ")
        print("\nFree:", end=" ")
        for bit in self.bitmap:
            print(bit, end=" ")
        print()

# Example usage
fs = BitVectorFreeSpace(16)
fs.print_bitmap()
block = fs.allocate_block()
print(f"Allocated block: {block}")
fs.free_block(5)
print(f"Freed block: 5")
print(f"Free blocks remaining: {fs.get_free_blocks_count()}")
